import sys

def main():
    H, W, N = map(int, sys.stdin.readline().split())
    grid = [['.' for _ in range(W)] for _ in range(H)]
    direction = 0  # 0: up, 1: right, 2: down, 3: left
    x, y = 0, 0  # Starting at (1,1) which is (0,0) in 0-indexed

    for _ in range(N):
        if grid[x][y] == '.':
            grid[x][y] = '#'
            direction = (direction + 1) % 4
        else:
            grid[x][y] = '.'
            direction = (direction - 1) % 4

        # Move forward
        if direction == 0:
            x = (x - 1) % H
        elif direction == 1:
            y = (y + 1) % W
        elif direction == 2:
            x = (x + 1) % H
        else:  # direction == 3
            y = (y - 1) % W

    for row in grid:
        print(''.join(row))

if __name__ == "__main__":
    main()
